import{_ as t,o,c as i,a2 as a}from"./chunks/framework.jisAoZJG.js";const u=JSON.parse('{"title":"Interface: SkillAuthoringContext","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://sqlrooms.org/api/ai/interfaces/SkillAuthoringContext.html"}]]},"headers":[],"relativePath":"api/ai/interfaces/SkillAuthoringContext.md","filePath":"api/ai/interfaces/SkillAuthoringContext.md"}'),r={name:"api/ai/interfaces/SkillAuthoringContext.md"};function n(s,e,l,d,c,h){return o(),i("div",null,[...e[0]||(e[0]=[a('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /api/ai/interfaces/SkillAuthoringContext.md for this page in Markdown format</div><p><a href="./../">@sqlrooms/ai</a> / SkillAuthoringContext</p><h1 id="interface-skillauthoringcontext" tabindex="-1">Interface: SkillAuthoringContext <a class="header-anchor" href="#interface-skillauthoringcontext" aria-label="Permalink to &quot;Interface: SkillAuthoringContext&quot;">​</a></h1><p>The capability surface the host exposes to the authoring agent. The agent may mention these names when drafting instructions; it may not mention concrete schema (see <code>forbiddenIdentifiers</code>).</p><p>All fields are generic lists of strings so the host controls its own vocabulary — this type carries no knowledge of any specific analytics app, service, or runtime.</p><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to &quot;Properties&quot;">​</a></h2><h3 id="services" tabindex="-1">services <a class="header-anchor" href="#services" aria-label="Permalink to &quot;services&quot;">​</a></h3><blockquote><p><strong>services</strong>: readonly <code>string</code>[]</p></blockquote><p>Named services the drafted skill may reference (e.g. the sub-apis of an <code>execute</code>-style tool the host exposes). Empty list is valid.</p><hr><h3 id="tools" tabindex="-1">tools <a class="header-anchor" href="#tools" aria-label="Permalink to &quot;tools&quot;">​</a></h3><blockquote><p><strong>tools</strong>: readonly <code>string</code>[]</p></blockquote><p>Leaf tools available at skill runtime (e.g. <code>querySQL</code>, <code>readFile</code>). Empty list is valid.</p><hr><h3 id="permissions" tabindex="-1">permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;permissions&quot;">​</a></h3><blockquote><p><strong>permissions</strong>: readonly <code>string</code>[]</p></blockquote><p>Permission keys the host recognizes. Currently unused by the manifest schema but surfaced in the system prompt for forward compatibility. Empty list is valid.</p><hr><h3 id="forbiddenidentifiers" tabindex="-1">forbiddenIdentifiers? <a class="header-anchor" href="#forbiddenidentifiers" aria-label="Permalink to &quot;forbiddenIdentifiers?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>forbiddenIdentifiers?</strong>: readonly <code>string</code>[]</p></blockquote><p>Identifiers (e.g. current table names) that must not appear verbatim in manifest fields or instructions. Matched case-insensitively on word boundaries. Optional — omit if the host has no contextual identifiers.</p><hr><h3 id="defaultrootid" tabindex="-1">defaultRootId? <a class="header-anchor" href="#defaultrootid" aria-label="Permalink to &quot;defaultRootId?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>defaultRootId?</strong>: <code>string</code></p></blockquote><p>Root the wizard writes to when <code>saveSkill</code> is called without an explicit <code>rootId</code>. Optional — the host may also require the agent to pass one.</p>',25)])])}const f=t(r,[["render",n]]);export{u as __pageData,f as default};
